sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county ?sviRecord ?sviScore ?stormEventCount
WHERE {
  ?state a goo:State ;
         goo:neighboringStates gokg:AlabamaState ;
         goo:neighboringStates gokg:GeorgiaState .
  ?county a goo:County ;
          goo:locatedInState ?state .
  BIND((2023 - 1) AS ?targetYear)
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear ?targetYear ;
             goo:sviOverallScore ?sviScore .
  FILTER (?sviScore >= 0.8)
  {
    SELECT ?county ?state (COUNT(DISTINCT ?event) AS ?stormEventCount)
    WHERE {
      BIND((2023 - 1) AS ?eventYear)
      ?event a goo:StormEventRecord ;
             goo:occurredInState ?state ;
             goo:occurredInCounty ?county ;
             goo:eventStartTime ?eventStart .
      FILTER (YEAR(?eventStart) = ?eventYear)
    }
    GROUP BY ?county ?state
  }
  FILTER (?stormEventCount >= 8)
}
ORDER BY DESC(?sviScore) DESC(?stormEventCount)
